<script setup lang="ts">
  const { isLoading = false } = defineProps<{ isLoading?: boolean }>();

  const route = useRoute();
  const router = useRouter();

  function selected(path: string, part: string) {
    return computed({
      get: () => route.path.startsWith(part),
      set: () => router.replace(path),
    });
  }

  const navigation = reactive(
    [
      {
        label: 'tags',
        icon: 'fa6-solid:tags',
        isSelected: selected('/tag/list', '/tag'),
      },
      {
        label: 'tasks',
        icon: 'fluent:tasks-app-24-filled',
        isSelected: selected('/task/list', '/task'),
      },
      {
        label: 'settings',
        icon: 'fa-solid:cog',
        isSelected: selected('/settings', '/settings'),
      },
    ].reverse(),
  );
</script>

<template>
  <Loading v-if="isLoading" />
  <div
    v-else
    class="max-w-md mx-auto h-100dvh flex flex-col overflow-hidden"
  >
    <TransitionFade
      v-if="$slots.header"
      tag="header"
      group
      class="p-2 flex justify-end items-start gap-2 uppercase min-h-[3.5rem]"
    >
      <slot name="header"></slot>
    </TransitionFade>
    <FlipScrollYStart
      v-if="$slots.default"
      id="content"
      class="flex-grow snap-proximity snap-y relative"
    >
      <main class="px-2 pt-2 flex flex-col gap-2">
        <div class="h-50dvh"></div>
        <slot name="default"></slot>
      </main>
    </FlipScrollYStart>
    <footer>
      <TransitionFade
        v-if="$slots.footer"
        group
        class="p-2 flex justify-end items-center gap-2"
      >
        <slot name="footer"></slot>
      </TransitionFade>
      <TransitionFade
        group
        class="p-2 grid grid-flow-col gap-2 justify-evenly"
      >
        <Toggle
          v-for="nav in navigation"
          :key="nav.icon"
          v-model="nav.isSelected"
          class="flex-wrap gap-0.5 text-[8px] px-3 max-w-min"
          flat
        >
          <Icon
            class="text-sm"
            :name="nav.icon"
          />
          {{ nav.label }}
        </Toggle>
      </TransitionFade>
    </footer>
  </div>
</template>

<style lang="scss" scoped></style>
